    def __init__(self, value):
        self.value = value
        self.grad = None

    def __repr__(self):
        return f'Variable({self.value})'

class Autograd:
    def __init__(self):
        self.cache = {}

    def forward(self, var):
        self.cache[var] = var.value
        return var

    def backward(self, var, grad):
        if var.grad is None:
            var.grad = grad
        else:
            var.grad += grad

        for child in self.cache[var]:
            child.backward(grad * child.grad)

